import java.util.Scanner;
import java.util.Arrays;

public class SecureBuffer {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        System.out.print("Enter your name: ");
        String userInput = scanner.nextLine();

        // Secure code generation to prevent buffer overflow
        int maxLength = Math.min(userInput.length(), 10);
        char[] buffer = Arrays.copyOf(userInput.toCharArray(), maxLength);

        System.out.println("Hello, " + String.valueOf(buffer));
    }
}

